import React, { createContext, useContext, useState, useCallback } from "react";

const CorridaEmAndamentoContext = createContext(null);

export function useCorridaEmAndamento() {
    const ctx = useContext(CorridaEmAndamentoContext);
    if (!ctx) throw new Error("useCorridaEmAndamento must be used within CorridaEmAndamentoProvider");
    return ctx;
}

/** { corridaId, enderecoOrigem, enderecoDestino, onFinalizar? } | null */
export function CorridaEmAndamentoProvider({ children }) {
    const [corridaModal, setCorridaModal] = useState(null);

    const openCorridaModal = useCallback((data) => {
        setCorridaModal(data);
    }, []);

    const closeCorridaModal = useCallback(() => {
        setCorridaModal(null);
    }, []);

    const value = {
        corridaModal,
        openCorridaModal,
        closeCorridaModal,
        /** Id da corrida atualmente em andamento no modal (para bloquear edição). */
        corridaEmAndamentoId: corridaModal?.corridaId ?? null,
    };

    return (
        <CorridaEmAndamentoContext.Provider value={value}>
            {children}
        </CorridaEmAndamentoContext.Provider>
    );
}
